export function includeHTML(callback){const elements=document.querySelectorAll('[w3-include-html]');let total=elements.length;if(total===0&&callback){callback();setupVersionSwitcher();}
elements.forEach(el=>{const file=el.getAttribute("w3-include-html");if(!file){total--;return;}
fetch(file).then(resp=>{if(!resp.ok){console.error(`Failed to load ${file}: ${resp.status} ${resp.statusText}`);throw new Error(`Page not found: ${resp.status}`);}
return resp.text();}).then(data=>{el.innerHTML=data;el.removeAttribute("w3-include-html");total--;if(total===0&&callback){callback();setupVersionSwitcher();if(typeof window.initThemeSwitcher==='function'){window.initThemeSwitcher();}}}).catch(err=>{console.error(`Include error for ${file}:`,err);el.innerHTML=`Include failed: ${err.message}`;total--;if(total===0&&callback){callback();setupVersionSwitcher();}});});}
export function setActive(){const navLinks=document.querySelectorAll('.nav-link');const currentPage=window.location.pathname.split("/").pop();if(navLinks.length===0){setTimeout(setActive,100);return;}
navLinks.forEach(link=>{const linkHref=link.getAttribute("href");if(linkHref===currentPage){link.classList.add("active");link.setAttribute("aria-current","page");}else{link.classList.remove("active");link.removeAttribute("aria-current");}});}
export function showPageWhenLoaded(){$(function(){$('body').show();});}
export function debounce(fn,delay=150){let t;return(...args)=>{clearTimeout(t);t=setTimeout(()=>fn(...args),delay);};}
export function jsonToItems(obj){return Object.entries(obj).map(([name,value])=>typeof value==="string"?{Name:name,Description:value}:{Name:name,...value});}
export function buildPillSection(root,id,values,{attr="data-type",onChange,useTypeClass=true}={}){const container=document.createElement("div");container.id=id;container.className="d-flex flex-wrap gap-1";values.forEach(v=>{const btn=document.createElement("button");btn.type="button";btn.className="btn btn-sm type-pill";if(useTypeClass){const sanitizedClass=`card-type-${v.replace(/\s+/g, '')}`;btn.classList.add(sanitizedClass);}
btn.setAttribute(attr,v);btn.setAttribute("data-selected","0");btn.textContent=v;container.appendChild(btn);});container.addEventListener("click",ev=>{const btn=ev.target.closest(`button[${attr}]`);if(!btn)return;const state=btn.getAttribute("data-selected")==="1";btn.setAttribute("data-selected",state?"0":"1");btn.classList.toggle("active",!state);if(onChange)onChange();});root.appendChild(container);return container;}
export function getSelectedPills(root,id,attr="data-type"){const zone=root.querySelector(`#${id}`);if(!zone)return[];return Array.from(zone.querySelectorAll(`button[${attr}][data-selected="1"]`)).map(btn=>btn.getAttribute(attr));}
export function filterText(query,item){if(!query)return true;return Object.values(item).some(v=>typeof v==="string"&&v.toLowerCase().includes(query));}
export function filterByTypes(item,types){if(!types.length)return true;return types.includes(item.Type);}
export function filterByClasses(item,classes){if(!classes.length)return true;return classes.includes(item.Class);}
export function filterByDamageBase(item,damageBases){if(!damageBases.length)return true;const damageBase=item["Damage Base"];if(!damageBase)return false;const match=String(damageBase).match(/\d+/);if(!match)return false;return damageBases.includes(match[0]);}
export function filterByEffect(item,hasEffectFilter){if(!hasEffectFilter.length)return true;const hasWithEffect=hasEffectFilter.includes("With Effect");const hasNoEffect=hasEffectFilter.includes("No Effect");if(hasWithEffect&&hasNoEffect)return true;const isNoneOrEmpty=(value)=>{if(!value)return true;const str=String(value).trim().toLowerCase();return str===""||str==="none"||str==="none.";};const effect=item.Effect||"";const setUpEffect=item["Set-Up Effect"]||"";const moveHasEffect=!isNoneOrEmpty(effect)||!isNoneOrEmpty(setUpEffect);if(hasWithEffect)return moveHasEffect;if(hasNoEffect)return!moveHasEffect;return true;}
export function filterByContestType(item,contestTypes){if(!contestTypes.length)return true;return contestTypes.includes(item["Contest Type"]);}
export function filterByContestEffect(item,contestEffects){if(!contestEffects.length)return true;return contestEffects.includes(item["Contest Effect"]);}
export function filterByRangeDistance(item,rangeDistances){if(!rangeDistances.length)return true;const range=item.Range||"";const variants=range.split(/;\s*or\s+/i).map(v=>v.trim());const distances=new Set();variants.forEach(variant=>{const parts=variant.split(',').map(p=>p.trim());parts.forEach(part=>{if(part.toLowerCase().includes('melee')){distances.add('Melee');}
const match=part.match(/^(\d+)$/);if(match){distances.add(match[1]);}
const keywordMatch=part.match(/^(Cone|Line|Burst|Close Blast|Blast)\s+(\d+)$/i);if(keywordMatch){distances.add(keywordMatch[2]);}});});return rangeDistances.some(d=>distances.has(d));}
export function filterByRangeKeyword(item,rangeKeywords){if(!rangeKeywords.length)return true;const range=item.Range||"";const variants=range.split(/;\s*or\s+/i).map(v=>v.trim());const keywords=new Set();variants.forEach(variant=>{const parts=variant.split(',').map(p=>p.trim());parts.forEach(part=>{part=part.replace(/\s*\([^)]*\)/g,'').trim();if(/^\d+$/.test(part))return;const orParts=part.split(/\s+or\s+/i);orParts.forEach(subPart=>{subPart=subPart.trim();const recoilMatch=subPart.match(/^Recoil\s+\d+\/\d+$/i);if(recoilMatch){keywords.add('Recoil');return;}
const asteriskMatch=subPart.match(/^(Cone|Line|Burst|Close Blast|Blast)\s+\d+\*$/i);if(asteriskMatch){keywords.add(asteriskMatch[1]);return;}
const keywordMatch=subPart.match(/^(Cone|Line|Burst|Close Blast|Blast)\s+\d+$/i);if(keywordMatch){keywords.add(keywordMatch[1]);return;}
const cleaned=subPart.replace(/\d+/g,'').trim();const lowerCleaned=cleaned.toLowerCase();if(cleaned&&lowerCleaned!=='melee'&&lowerCleaned!=='target'&&lowerCleaned!=='targets'){keywords.add(cleaned);}});});});return rangeKeywords.some(k=>keywords.has(k));}
export function filterByTargeting(item,targeting){if(!targeting.length)return true;const range=item.Range||"";const hasSingleTarget=targeting.includes("Single Target");const hasMultiTarget=targeting.includes("Multi Target");if(hasSingleTarget&&hasMultiTarget)return true;const variants=range.split(/;\s*or\s+/i).map(v=>v.trim());let isSingleTarget=false;let isMultiTarget=false;variants.forEach(variant=>{if(/\b1\s+target\b/i.test(variant)){isSingleTarget=true;}
if(/\b(cone|line|burst|blast|all)\b/i.test(variant)||/\b([2-9]|\d{2,})\s+targets?\b/i.test(variant)){isMultiTarget=true;}});if(hasSingleTarget&&isSingleTarget)return true;if(hasMultiTarget&&isMultiTarget)return true;return false;}
export function setupVersionSwitcher(){const links=document.querySelectorAll('.dropdown-menu a.dropdown-item');const currentPath=window.location.pathname;const hash=window.location.hash;const currentFile=currentPath.split('/').pop()||'index.html';links.forEach(link=>{const href=link.getAttribute('href');if(!href)return;const newPath=href.replace(/[^/]*\.html$/,currentFile);link.href=newPath+hash;});}